UPDATE sys_menu
SET display_flag = #{displayFlag},
    update_date  = #{updateDate},
    update_by    = #{updateUserId}
WHERE id = #{id}

UPDATE sys_menu
SET lft = #{node.lft},
    rgt = #{node.rgt}
WHERE id = #{node.id}

UPDATE sys_menu
SET parent_id = #{node.parentId}
WHERE id = #{node.id}

UPDATE sys_menu
SET rgt = rgt + #{offset}
WHERE rgt >= #{from}

UPDATE sys_menu
SET lft = lft + #{offset}
WHERE lft >= #{from}

UPDATE sys_menu
SET lft = lft + #{offset},
    rgt = rgt + #{offset}
WHERE lft BETWEEN #{from} AND #{to}
